condition.value:
from(
  event_type = "ingress_auth"
)
where(
    service = NOCASE("o365")
  AND
    SUBQUERY("Low Cost VPN Providers")
  AND
    result = NOCASE("SUCCESS")
)

from(
  event_type = "advanced_malware"
)
where(
    NOT
      severity = "BENIGN"
  AND
    severity = /.+/
)

from(
    event_type = "third_party_alert"
  AND
    event_subtype = "aws_guard_duty"
)
where(
  type = NOCASE("Attacksequence:eks/compromisedcluster")
)
